package org.example;

import io.xlate.edi.stream.EDIInputFactory;
import io.xlate.edi.stream.EDIStreamEvent;
import io.xlate.edi.stream.EDIStreamReader;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.*;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.List;

@Service
public class EdiConverter {

    @Value("${edi.output.path:C:/Users/35311/Desktop/EDI_DEMO/csv_output/}")
    private String outputDirPath;

    public void processFile(File inputFile) {
        Path outputPath = Paths.get(outputDirPath, inputFile.getName().replaceAll("(?i)\\.(edi|txt)$", ".csv"));
        EDIInputFactory factory = EDIInputFactory.newFactory();

        try (InputStream is = new FileInputStream(inputFile);
             EDIStreamReader reader = factory.createEDIStreamReader(is);
             PrintWriter pw = new PrintWriter(Files.newBufferedWriter(outputPath, StandardCharsets.UTF_8))) {

            pw.println("Sender_Name,Receiver_Name,Ref_IA,Item_ID,UPC,Activity,Price,Store_ID,Quantity");

            String sender = "N/A", receiver = "N/A", ia = "N/A";
            String item = "N/A", upc = "N/A", activity = "N/A", price = "N/A";

            while (reader.hasNext()) {
                EDIStreamEvent event = reader.next();

                if (event == EDIStreamEvent.START_SEGMENT) {
                    String segmentId = reader.getText();
                    // Load all elements of this segment into a list immediately
                    List<String> elements = readSegment(reader);

                    switch (segmentId) {
                        case "N1" -> {
                            String role = getVal(elements, 1);
                            if ("FR".equals(role)) sender = getVal(elements, 2);
                            else if ("TO".equals(role)) receiver = getVal(elements, 2);
                        }
                        case "N9" -> {
                            if ("IA".equals(getVal(elements, 1))) ia = getVal(elements, 2);
                        }
                        case "LIN" -> {
                            item = getVal(elements, 2); // LIN03 is usually index 2 (0-based)
                            upc = getVal(elements, 4);  // LIN05 is usually index 4
                        }
                        case "ZA" -> activity = getVal(elements, 1);
                        case "CTP" -> price = getVal(elements, 3);
                        case "SDQ" -> {
                            // SDQ can contain multiple Store/Qty pairs.
                            // Standard 852: SDQ03=Store1, SDQ04=Qty1, SDQ05=Store2...
                            for (int i = 3; i < elements.size(); i += 2) {
                                String store = getVal(elements, i);
                                String qty = getVal(elements, i + 1);
                                if (!"N/A".equals(store)) {
                                    pw.printf("%s,%s,%s,%s,%s,%s,%s,%s,%s%n",
                                            sender, receiver, ia, item, upc, activity, price, store, qty);
                                }
                            }
                        }
                    }
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    // Helper to drain the current segment into a list so we can access by index
    private List<String> readSegment(EDIStreamReader reader) throws Exception {
        List<String> elements = new ArrayList<>();
        while (reader.hasNext()) {
            EDIStreamEvent event = reader.next();
            if (event == EDIStreamEvent.ELEMENT_DATA) {
                elements.add(reader.getText());
            } else if (event == EDIStreamEvent.END_SEGMENT) {
                break;
            }
        }
        return elements;
    }

    // Safe access to the list (using 1-based indexing to match EDI specs)
    private String getVal(List<String> elements, int index) {
        int listIndex = index - 1;
        return (listIndex >= 0 && listIndex < elements.size()) ? elements.get(listIndex) : "N/A";
    }
}

package org.example;

import io.xlate.edi.stream.EDIInputFactory;
import io.xlate.edi.stream.EDIStreamEvent;
import io.xlate.edi.stream.EDIStreamReader;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.*;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.List;

@Service
public class EdiConverter {

    @Value("${edi.output.path:data/output/}")
    private String outputDirPath;

    public void processFile(File inputFile) {
        Path outputPath = Paths.get(outputDirPath, inputFile.getName().replaceAll("(?i)\\.(edi|txt)$", ".csv"));
        EDIInputFactory factory = EDIInputFactory.newFactory();

        try (InputStream is = new FileInputStream(inputFile);
             EDIStreamReader reader = factory.createEDIStreamReader(is);
             PrintWriter pw = new PrintWriter(Files.newBufferedWriter(outputPath, StandardCharsets.UTF_8))) {

            pw.println("Product_ID,Vendor_PN,Activity_Code,Quantity,UOM,Report_Date");

            String productId = "N/A", vendorPn = "N/A";
            String reportDate = "N/A";

            while (reader.hasNext()) {
                EDIStreamEvent event = reader.next();

                if (event == EDIStreamEvent.START_SEGMENT) {
                    String segmentId = reader.getText();
                    // Load all elements of this segment into a list immediately
                    List<String> elements = readSegment(reader);

                    switch (segmentId) {
                        case "XQ" -> {
                            // XQ02 is the start date of the reporting period
                            reportDate = getVal(elements, 2);
                        }
                        case "LIN" -> {
                            // LIN03 is Product_ID (UPC/GTIN), LIN05 is Vendor_PN
                            productId = getVal(elements, 3);
                            vendorPn = getVal(elements, 5);
                        }
                        case "ZA" -> {
                            // ZA01 = Activity Code (QA, QS, QO, etc.)
                            // ZA02 = Quantity
                            // ZA03 = Unit of Measure
                            String activityCode = getVal(elements, 1);
                            String quantity = getVal(elements, 2);
                            String uom = getVal(elements, 3);
                            pw.printf("%s,%s,%s,%s,%s,%s%n",
                                    productId, vendorPn, activityCode, quantity, uom, reportDate);
                        }
                    }
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    // Helper to drain the current segment into a list so we can access by index
    private List<String> readSegment(EDIStreamReader reader) throws Exception {
        List<String> elements = new ArrayList<>();
        while (reader.hasNext()) {
            EDIStreamEvent event = reader.next();
            if (event == EDIStreamEvent.ELEMENT_DATA) {
                elements.add(reader.getText());
            } else if (event == EDIStreamEvent.END_SEGMENT) {
                break;
            }
        }
        return elements;
    }

    // Safe access to the list (using 1-based indexing to match EDI specs)
    private String getVal(List<String> elements, int index) {
        int listIndex = index - 1;
        return (listIndex >= 0 && listIndex < elements.size()) ? elements.get(listIndex) : "N/A";
    }
}

plugins {
    id 'org.springframework.boot' version '3.4.3'
    id 'io.spring.dependency-management' version '1.1.7'
    id 'java'
}

group = 'org.example'
version = '1.0-SNAPSHOT'

java {
    toolchain {
        languageVersion = JavaLanguageVersion.of(21)
    }
}

repositories {
    // Standard repository for most Java libraries
    mavenCentral()
}

dependencies {
    // Spring Boot Starter - Core Spring Framework
    implementation 'org.springframework.boot:spring-boot-starter'

    // StAEDI (Standard EDI parser)
    implementation 'io.xlate:staedi:1.21.0'

    // Standard JUnit for testing
    testImplementation platform('org.junit:junit-bom:5.10.0')
    testImplementation 'org.junit.jupiter:junit-jupiter'
}

test {
    useJUnitPlatform()
}

springBoot {
    mainClass = null
}

